248	/**
249	 * KRN-09 — kind of substitution applied to a curtain-wall grid cell.
250	 *
251	 * - `empty`: leave the cell open (no glass, no solid panel; mullions stay).
252	 * - `system`: render the cell as a solid panel using a registered
253	 *   `materialKey`. Falls back to glass if no `materialKey` is supplied.
254	 * - `family_instance`: instantiate a custom family at this cell. Until
255	 *   FAM-01 lands the renderer paints a placeholder panel and emits a TODO.
256	 */
257	export type CurtainPanelOverrideKind = 'empty' | 'system' | 'family_instance';
258	
259	export type CurtainPanelOverride = {
260	  kind: CurtainPanelOverrideKind;
261	  /** For `family_instance` overrides — id of the family type to instantiate. */
262	  familyTypeId?: string | null;
263	  /** For `system` overrides — `materialKey` resolved against the MAT-01 registry. */
264	  materialKey?: string | null;
265	};
