1359	       * `boundaryMm` is a closed plan polygon (≥ 3 vertices).
1360	       * `zMm` is the underside elevation (filled by the engine from the host
1361	       * roof's eave elevation when the command omits it).
1362	       */
1363	      kind: 'soffit';
1364	      id: string;
1365	      name?: string;
1366	      boundaryMm: XY[];
1367	      hostRoofId?: string | null;
1368	      thicknessMm: number;
1369	      zMm: number;
1370	      pinned?: boolean;
1371	      phaseCreated?: string | null;
1372	      phaseDemolished?: string | null;
1373	    }
1374	  | {
1375	      /** SUN-V3-01 — project-level sun & shadow study singleton. */
1376	      kind: 'sun_settings';
1377	      id: string;
