1449	export type CorrelationDigestConsistencyV1 = {
1450	  format: 'correlationDigestConsistency_v1';
1451	
1452	  staleRowsRelativeToPackageDigest: Record<string, unknown>[];
1453	
1454	  rowsMissingCorrelationDigest: { kind: string; id: string }[];
